package com.example.raithavarta

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.viewpager2.widget.ViewPager2
import com.example.raithavarta.data.local.TipEntity
import com.example.raithavarta.ui.adapter.TipPagerAdapter

class MainActivity : AppCompatActivity() {

    private lateinit var viewPager: ViewPager2

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        setContentView(R.layout.activity_main)

        viewPager = findViewById(R.id.viewPager)

        val tips = listOf(

            TipEntity(
                title = "Paddy Pest Control",
                description = "Spray pesticide early morning for better protection.",
                imageUrl = "https://images.unsplash.com/photo-1501004318641-b39e6451bec6",
                cropType = "Paddy",
                language = "English"
            ),

            TipEntity(
                title = "Tomato Watering",
                description = "Water tomato plants during evening to reduce evaporation.",
                imageUrl = "https://images.unsplash.com/photo-1592924357228-91a4daadcfea",
                cropType = "Tomato",
                language = "English"
            ),

            TipEntity(
                title = "Coconut Farming",
                description = "Add organic fertilizer every 3 months.",
                imageUrl = "https://images.pexels.com/photos/3887927/pexels-photo-3887927.jpeg",
                cropType = "Coconut",
                language = "English"
            ),

            TipEntity(
                title = "Areca Nut Care",
                description = "Maintain proper drainage during rainy season.",
                imageUrl = "data:image/jpeg;base64,",
                cropType = "Areca Nut",
                language = "English"
            )
        )

        val adapter = TipPagerAdapter(tips)

        viewPager.adapter = adapter

        viewPager.orientation = ViewPager2.ORIENTATION_HORIZONTAL

        viewPager.offscreenPageLimit = 3
    }
}